1	import { describe, it, expect } from "vitest";
2	import { processScenario, type Item } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // --- Base premiums for main items (with fee) ---
15	  it("single sword (no modifiers, first contract) → premium 115 G (100 base + 10 first ins + 5 fee)", () => {
16	    const result = processScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result.results[0]).toEqual({ premium: 115 });
21	  });
22	  it("single amulet (no modifiers, first contract) → premium 71 G (60 + 6 + 5)", () => {
23	    const result = processScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result.results[0]).toEqual({ premium: 71 });
28	  });
29	  it("single staff (no modifiers, first contract) → premium 93 G (80 + 8 + 5)", () => {
30	    const result = processScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result.results[0]).toEqual({ premium: 93 });
35	  });
36	  it("single potion (no modifiers, first contract) → premium 49 G (40 + 4 + 5)", () => {
37	    const result = processScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result.results[0]).toEqual({ premium: 49 });
42	  });
43	
44	  // --- Components base premiums ---
45	  it("2 runes → base 50 G (premium 60 G with first ins + fee)", () => {
46	    const result = processScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
49	    });
50	    expect(result.results[0]).toEqual({ premium: 60 });
51	  });
52	  it("3 runes (block) → base 60 G (premium 71 with first ins + fee)", () => {
53	    const result = processScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [
56	        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
57	      ],
58	    });
59	    expect(result.results[0]).toEqual({ premium: 71 });
60	  });
61	  it("4 runes → base 100 G (premium 115 with first ins + fee)", () => {
62	    const result = processScenario({
63	      customer: { yearsWithMHPCO: 0 },
64	      steps: [
65	        {
66	          op: "quote",
67	          items: [
68	            { type: "rune" },
69	            { type: "rune" },
70	            { type: "rune" },
71	            { type: "rune" },
72	          ],
73	        },
74	      ],
75	    });
76	    expect(result.results[0]).toEqual({ premium: 115 });
77	  });
78	  it("7 runes → base 175 G (premium 198 with first ins + fee, rounded up)", () => {
79	    const items: Item[] = Array.from({ length: 7 }, () => ({ type: "rune" }));
80	    const result = processScenario({
81	      customer: { yearsWithMHPCO: 0 },
82	      steps: [{ op: "quote", items }],
83	    });
84	    expect(result.results[0]).toEqual({ premium: 198 });
85	  });
86	
87	  // --- Alike components ---
88	  it("2 runes + 1 moonstone → base 75 G (premium 88 with first ins + fee)", () => {
89	    const result = processScenario({
90	      customer: { yearsWithMHPCO: 0 },
91	      steps: [
92	        {
93	          op: "quote",
94	          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
95	        },
96	      ],
97	    });
98	    expect(result.results[0]).toEqual({ premium: 88 });
99	  });
100	  it("3 runes + 3 moonstones → base 120 G (premium 137)", () => {
101	    const items: Item[] = [
102	      ...Array.from({ length: 3 }, () => ({ type: "rune" })),
103	      ...Array.from({ length: 3 }, () => ({ type: "moonstone" })),
104	    ];
105	    const result = processScenario({
106	      customer: { yearsWithMHPCO: 0 },
107	      steps: [{ op: "quote", items }],
108	    });
109	    expect(result.results[0]).toEqual({ premium: 137 });
110	  });
111	
112	  // --- Item-specific modifiers ---
113	  it("cursed sword (first contract) → premium 165 G (100 base + 50 curse + 10 first ins + 5 fee)", () => {
114	    const result = processScenario({
115	      customer: { yearsWithMHPCO: 0 },
116	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
117	    });
118	    expect(result.results[0]).toEqual({ premium: 165 });
119	  });
120	  it.todo("sword enchantment 5 (first contract) → high-enchantment surcharge 30% applies");
121	  it.todo("sword enchantment 4 (first contract) → no high-enchantment surcharge");
122	  it.todo("cursed sword enchantment 5 → both surcharges apply");
123	
124	  // --- Policy-wide modifiers ---
125	  it.todo("customer 2 years → loyalty discount applies");
126	  it.todo("customer 1 year → no loyalty discount");
127	  it.todo("second contract → follow-up discount 15% applies");
128	
129	  // --- Modifier scope (item vs policy) ---
130	  it.todo("cursed sword + plain amulet → cursed surcharge applies to sword only; policy base 160, after curse 210 before fee");
131	
132	  // --- Rounding ---
133	  it.todo("premium yielding 197.5 G → rounded UP to 198 G");
134	
135	  // --- Integration examples ---
136	  it.todo("newcomer with cursed sword → premium 165 G");
137	  it.todo("long-standing customer's second contract with cursed enchanted sword → premium 160 G");
138	
139	  // --- Claim: standard reimbursement ---
140	  it.todo("steel sword enchantment 3, damage 500 G → payout 400 G (500 - 100 deductible)");
141	  it.todo("damage to rune (insurance 250 G), damage 200 G → payout 100 G");
142	
143	  // --- Claim: enchantment threshold ---
144	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
145	
146	  // --- Claim: dragon material ---
147	  it.todo("dragon sword enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
148	
149	  // --- Claim: dragon + enchantment ---
150	  it.todo("dragon sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
151	  it.todo("dragon sword enchantment exactly 8, damage 1000 G → payout 400 G");
152	
153	  // --- Deductible per damage event ---
154	  it.todo("dragon attack damages sword 500 + amulet 300 → payout 600 G (deductible per item)");
155	
156	  // --- Payout rounding ---
157	  it.todo("payout calc yielding 350.5 G → rounded DOWN to 350 G");
158	
159	  // --- Multiple items of same type ---
160	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
161	  it.todo("two swords damaged separately → each entry has own deductible");
162	  it.todo("damages array has more entries of a type than policy covers → CLI rejects (non-zero exit)");
163	
164	  // --- Cap exhaustion ---
165	  it.todo("sword + amulet → insurance sum 1600, cap 3200");
166	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
167	  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
168	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remainingCap 600");
169	  it.todo("sword (cap 2000), second claim 1500 after 1500 → payout 600, remainingCap 0");
170	
171	  // --- Edge cases ---
172	  it.todo("quote with unknown item type → CLI exits non-zero, writes stderr, no results");
173	  it.todo("claim references item not in policy → CLI exits non-zero");
174	  it.todo("claim with negative damage amount → CLI exits non-zero");
175	});
