1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	};
68	
69	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
70	  rune: 25,
71	  moonstone: 25,
72	};
73	
74	const ITEM_BASE_PREMIUMS: Record<string, number> = {
75	  ...MAIN_ITEM_BASE_PREMIUMS,
76	  ...COMPONENT_BASE_PREMIUMS,
77	};
78	
79	const COMPONENT_TYPES = new Set(Object.keys(COMPONENT_BASE_PREMIUMS));
80	const BLOCK_SIZE = 3;
81	const BLOCK_BASE = 60;
82	
83	const CURSE_SURCHARGE_RATE = 0.5;
84	
85	const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;
86	
87	const componentGroupBase = (count: number, unitBase: number): number => {
88	  if (count === BLOCK_SIZE) return BLOCK_BASE;
89	  return count * unitBase;
90	};
91	
92	const itemSurcharge = (item: Item, base: number): number => {
93	  let surcharge = 0;
94	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
95	  return surcharge;
96	};
97	
98	const quotePremium = (items: Item[]): number => {
99	  let policyBase = 0;
100	  let itemSurchargeTotal = 0;
101	  const componentCounts = new Map<string, number>();
102	
103	  for (const item of items) {
104	    if (COMPONENT_TYPES.has(item.type)) {
105	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
106	    } else {
107	      const base = itemBase(item.type);
108	      policyBase += base;
109	      itemSurchargeTotal += itemSurcharge(item, base);
110	    }
111	  }
112	
113	  for (const [type, count] of componentCounts) {
114	    const groupBase = componentGroupBase(count, itemBase(type));
115	    policyBase += groupBase;
116	  }
117	
118	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
119	  const total = policyBase + itemSurchargeTotal + firstInsurance;
120	  return roundUp(total) + PROCESSING_FEE;
121	};
122	
123	export const processScenario = (scenario: Scenario): ScenarioResult => {
124	  const results: StepResult[] = scenario.steps.map((step) => {
125	    if (step.op === "quote") {
126	      return { premium: quotePremium(step.items) };
127	    }
128	    return { payout: 0, remainingCap: 0 };
129	  });
130	  return { results };
131	};
